; ===========================================================================
; NES ROM Disassembly - Annotated Version
; ===========================================================================
; Original disassembly by da65 V2.18
; Annotations added for readability and game logic understanding
;
; ROM Structure:
;   PRG-ROM: 32 KB ($8000-$FFFF) - Single bank, NROM mapper (mapper 0)
;   Vectors at $FFFA:
;     NMI:   $8082 (NMI_Handler / nmi_handler)
;     RESET: $8000 (Reset / reset_handler)
;     IRQ:   $FFF0 (IRQ_Handler - unused, points into data)
;
; Memory Map:
;   $0000-$07FF: 2 KB internal RAM
;   $2000-$2007: PPU registers
;   $4000-$4017: APU and I/O registers
;   $8000-$FFFF: PRG-ROM
;
; ===========================================================================
; RAM Variable Definitions
; ===========================================================================
;
; Zero Page ($0000-$00FF):
;   $0000-$0001: temp_ptr          - Indirect pointer for PPU buffer processing
;                                     and jump_table_dispatch
;   $0002-$0003: temp_work         - Temporary working variables
;   $0004-$0005: dispatch_ret_addr - Return address saved by jump_table_dispatch
;   $0006-$0007: dispatch_target   - Jump target address for jump_table_dispatch
;   $0008:       entity_index      - Current entity slot index
;   $0009:       frame_counter     - Incremented every non-paused NMI frame
;
; OAM Buffer ($0200-$02FF):
;   64 sprites x 4 bytes each:
;     +0: Y position (set to $F8 to hide sprite)
;     +1: Tile index
;     +2: Attributes (palette, flip, priority)
;     +3: X position
;
; PPU Update Buffers ($0300-$03FF):
;   $0300:       ppu_buf_write_ptr  - Current write position in buffer
;   $0301+:      PPU buffer command data (addr_hi, addr_lo, length, data...)
;   $0340:       attr_buf_ptr       - Attribute table buffer pointer
;   $0341+:      Attribute table update data
;   $03F9+:      Attribute accumulator
;
; Entity Tables ($0400-$04FF):
;   Various entity position, state, and collision data
;   $046A:       entity_alloc_index
;
; Entity Data ($06A0-$06FF):
;   $06A0:       scroll_tile_offset
;   $06A1-$06AD: entity_type_table  - Type ID for each of 13 entity slots
;   $06BC:       entity_spawn_counter
;   $06CC:       difficulty_flag
;   $06D4:       palette_cycle_index
;   $06E0:       rng_cycle_index    - Cycles 0-2
;   $06E1-$06E3: rng_add_values     - Added to RNG accumulators
;   $06E4-$06F3: rng_state          - 15 bytes of RNG/timing accumulators
;   $06FC:       joy1_buttons       - Controller 1 current frame buttons
;                                     Bit 7=A, 6=B, 5=Select, 4=Start
;                                     Bit 3=Up, 2=Down, 1=Left, 0=Right
;   $06FD:       joy2_buttons       - Controller 2 current frame buttons
;
; Game State ($0700-$07FF):
;   $0704:       player2_active
;   $0710:       level_tileset
;   $0715:       checkpoint_flag
;   $0717:       demo_playback_idx
;   $0718:       demo_frame_count
;   $0719:       level_scroll_pos
;   $071A:       current_level_id
;   $071B:       level_data_ptr
;   $071E:       level_segment_count
;   $071F:       scroll_update_flag
;   $0720:       base_nametable_hi  - $20 or $24
;   $0721:       base_nametable_lo  - Column offset within nametable
;   $0722:       sprite_hit_flag    - Nonzero = use sprite 0 hit for scroll split
;   $0725:       entity_spawn_flag  - Current spawn position
;   $0726:       attr_update_side   - Left/right side for attribute writes
;   $0728:       entity_spawn_pos
;   $072D-$072F: entity_map_ptrs
;   $0730-$0732: entity_state_table - State for entity spawn slots
;   $0733:       battle_type
;   $0734:       entity_spawn_id
;   $0735:       entity_slot_count
;   $073C:       substep_counter    - Sub-step within current submode
;   $073F:       scroll_x           - Horizontal scroll position
;   $0740:       scroll_y           - Vertical scroll position
;   $0743:       powerup_flag
;   $0744:       palette_select
;   $0747:       anim_timer         - Animation frame delay counter
;   $0749:       scroll_sub_pos     - Sub-pixel scroll accumulator
;   $074A-$074B: joy_prev           - Previous frame controller state
;                                     Used for detecting new presses
;   $074E:       hud_counter        - HUD display mode / player indicator
;   $0750:       level_header_byte
;   $0751:       continue_level_id
;   $0752:       game_variant       - 0=normal, 1=alt, 2=special
;   $0753:       two_player_flag
;   $0754:       lives_count
;   $0756:       palette_override
;   $0757:       music_request
;   $0758:       warp_flag
;   $0759:       level_complete
;   $075A:       remaining_lives
;   $075B:       bonus_level_id
;   $075C:       sublevel_id
;   $075D:       spawn_trigger
;   $075F:       world_number       - Current world (0-7)
;   $0760:       world_sublevel
;   $0761:       start_lives
;   $0764:       death_counter
;   $0766:       world_start
;   $0767:       sublevel_start
;   $0768:       scroll_accumulator
;   $0769:       bonus_complete_flag
;   $076A:       continue_flag
;   $076B:       option_cursor_pos
;   $0770:       game_mode          - 0=init/title, 1=gameplay, 2=battle, 3=cutscene
;   $0772:       game_submode       - Sub-state within current game_mode
;   $0773:       ppu_update_index   - Which PPU buffer set to process (0-5)
;   $0774:       rendering_enabled  - Nonzero = rendering active
;   $0776:       nmi_control_flags  - Bit 0: paused, Bit 7: pause acknowledged
;   $0777:       frame_delay        - Countdown for pause debounce
;   $0778:       ppuctrl_shadow     - Shadow of PPUCTRL ($2000) register
;   $0779:       ppumask_shadow     - Shadow of PPUMASK ($2001) register
;   $077A:       option_toggle      - Menu option A/B toggle
;   $077F:       timer_base         - Divider for slow timer group (resets to 20)
;   $0780-$07A3: general_timers[36] - Decremented each frame (fast: 0-20, slow: 21-35)
;   $07A0:       transition_timer
;   $07A1:       level_end_flag
;   $07A2:       start_delay_timer
;   $07A7-$07A8: input_state_flags  - Used for RNG feedback generation
;   $07B0-$07CF: sound_state        - Sound driver state variables
;   $07B2:       sound_id           - Currently playing sound effect ID
;   $07BB:       sound_timer        - Sound effect duration counter
;   $07C6:       sound_trigger      - Trigger byte for new sound
;   $07D7-$07DC: high_score         - 6 bytes BCD (most significant first)
;   $07DD-$07E2: current_score      - 6 bytes BCD (most significant first)
;   $07F8-$07FA: checkpoint_data
;   $07FC:       b_button_flag
;   $07FD:       continue_world
;   $07FF:       warm_boot_magic    - Set to $A5; if present on reset,
;                                     high score is preserved (warm boot)
;
; ===========================================================================

