; ===========================================================================
; RESET VECTOR ENTRY POINT
; Called on power-on and reset. Initializes hardware, checks for warm boot,
; clears RAM, sets up PPU, and enters infinite loop (NMI-driven game).
; ===========================================================================
reset_handler:  sei                                     ; 8000 78                       x ; Disable interrupts
        cld                                     ; 8001 D8                       . ; Clear decimal mode (not used on NES but good practice)
        lda     #$10                            ; 8002 A9 10                    .. ; PPUCTRL: enable NMI, select pattern tables
        sta     PPUCTRL                         ; 8004 8D 00 20                 .. ; Write to PPUCTRL
        ldx     #$FF                            ; 8007 A2 FF                    .. ; Set stack pointer to $01FF
        txs                                     ; 8009 9A                       . ; Transfer X to stack pointer
wait_vblank_1:  lda     PPUSTATUS                       ; 800A AD 02 20                 .. ; Wait for first VBlank
        bpl     wait_vblank_1                           ; 800D 10 FB                    .. ; Loop until VBlank flag set
wait_vblank_2:  lda     PPUSTATUS                       ; 800F AD 02 20                 .. ; Wait for second VBlank (PPU warm-up)
        bpl     wait_vblank_2                           ; 8012 10 FB                    .. ; Loop until VBlank flag set
        ldy     #$FE                            ; 8014 A0 FE                    .. ; Y = $FE (cold boot marker)
        ldx     #$05                            ; 8016 A2 05                    .. ; X = 5 (check 6 high score digits)
check_high_score_valid:  lda     L07D7,x                         ; 8018 BD D7 07                 ... ; Load high score digit
        cmp     #$0A                            ; 801B C9 0A                    .. ; Is digit >= 10? (invalid BCD)
        bcs     cold_boot_init                           ; 801D B0 0C                    .. ; If invalid, jump to cold boot
        dex                                     ; 801F CA                       .
        bpl     check_high_score_valid                           ; 8020 10 F6                    ..
        lda     $07FF                           ; 8022 AD FF 07                 ... ; Check warm boot magic byte at $07FF
        cmp     #$A5                            ; 8025 C9 A5                    .. ; Magic value $A5 = warm boot
        bne     cold_boot_init                           ; 8027 D0 02                    .. ; If not warm boot, cold boot init
        ldy     #$D6                            ; 8029 A0 D6                    .. ; Y = $D6 (warm boot: preserve some RAM)
cold_boot_init:  jsr     ram_init                           ; 802B 20 CC 90                  .. ; Clear RAM (amount depends on boot type)
        sta     DMC_RAW                         ; 802E 8D 11 40                 ..@ ; Clear DMC raw output
        sta     $0770                           ; 8031 8D 70 07                 .p. ; Set game_mode = 0 (init/title)
        lda     #$A5                            ; 8034 A9 A5                    .. ; Warm boot magic value
        sta     $07FF                           ; 8036 8D FF 07                 ... ; Store magic to $07FF for next reset check
        sta     $07A7                           ; 8039 8D A7 07                 ... ; Initialize input state flags
        lda     #$0F                            ; 803C A9 0F                    .. ; Enable all sound channels
L8040           := * + 2
        sta     SND_CHN                         ; 803E 8D 15 40                 ..@ ; Write to SND_CHN ($4015)
        lda     #$06                            ; 8041 A9 06                    .. ; PPUMASK: show bg+sprites in left 8px
        sta     PPUMASK                         ; 8043 8D 01 20                 .. ; Write to PPUMASK
        jsr     oam_clear_all                           ; 8046 20 20 82                   . ; Clear all OAM sprites (move offscreen)
        jsr     ppu_initial_setup                           ; 8049 20 19 8E                  .. ; Initial PPU setup (clear nametables)
        inc     $0774                           ; 804C EE 74 07                 .t. ; Enable rendering flag
        lda     $0778                           ; 804F AD 78 07                 .x. ; Load PPUCTRL shadow
        ora     #$80                            ; 8052 09 80                    .. ; Set bit 7 (enable NMI)
        jsr     set_ppuctrl                           ; 8054 20 ED 8E                  .. ; Write to PPUCTRL and shadow
infinite_loop:  jmp     infinite_loop                           ; 8057 4C 57 80                 LW. ; Infinite loop; NMI drives the game from here

