; ===========================================================================
; NMI HANDLER (VBlank Interrupt)
; Called every frame during VBlank. This is the main game loop driver.
; Performs in order:
;   1. PPU register updates (PPUCTRL/PPUMASK)
;   2. OAM DMA transfer (sprites)
;   3. PPU buffer processing (nametable/palette updates)
;   4. Sound driver update
;   5. Controller reading
;   6. Pause check
;   7. Score comparison (high score update)
;   8. Timer/animation decrements
;   9. RNG state update (LFSR)
;  10. Sprite 0 hit split (for status bar)
;  11. Scroll register writes
;  12. Game mode dispatch
; ===========================================================================
nmi_handler:
        lda     $0778                           ; 8082 AD 78 07                 .x. ; Load PPUCTRL shadow register
        and     #$7F                            ; 8085 29 7F                    ). ; Clear NMI enable bit (bit 7)
        sta     $0778                           ; 8087 8D 78 07                 .x. ; Store back to shadow
        and     #$7E                            ; 808A 29 7E                    )~ ; Keep only pattern table / nametable bits
        sta     PPUCTRL                         ; 808C 8D 00 20                 .. ; Write to PPUCTRL (NMI off during handler)
        lda     $0779                           ; 808F AD 79 07                 .y. ; Load PPUMASK shadow
        and     #$E6                            ; 8092 29 E6                    ). ; Mask to disable rendering bits temporarily
        ldy     $0774                           ; 8094 AC 74 07                 .t. ; Check if rendering is enabled
        bne     nmi_set_ppumask                           ; 8097 D0 05                    .. ; If rendering disabled, skip mask update
        lda     $0779                           ; 8099 AD 79 07                 .y. ; Load full PPUMASK shadow
        ora     #$1E                            ; 809C 09 1E                    .. ; Enable sprites and background
nmi_set_ppumask:  sta     $0779                           ; 809E 8D 79 07                 .y. ; Store PPUMASK shadow
        and     #$E7                            ; 80A1 29 E7                    ). ; Mask off sprite/bg enable for partial update
        sta     PPUMASK                         ; 80A3 8D 01 20                 .. ; Write to PPUMASK (rendering partially off)
        ldx     PPUSTATUS                       ; 80A6 AE 02 20                 .. ; Read PPUSTATUS to reset address latch
        lda     #$00                            ; 80A9 A9 00                    .. ; A = 0
        jsr     clear_scroll                           ; 80AB 20 E6 8E                  .. ; Clear scroll position
        sta     OAMADDR                         ; 80AE 8D 03 20                 .. ; Set OAM address to 0
        lda     #$02                            ; 80B1 A9 02                    .. ; OAM DMA from page $02
        sta     OAMDMA                          ; 80B3 8D 14 40                 ..@ ; Trigger OAM DMA transfer
        ldx     $0773                           ; 80B6 AE 73 07                 .s. ; Load PPU update index
        lda     ppu_buffer_addr_lo,x                         ; 80B9 BD 5A 80                 .Z. ; Get buffer address low byte from table
        sta     L0000                           ; 80BC 85 00                    .. ; Store to temp_ptr low
        lda     ppu_buffer_addr_hi,x                         ; 80BE BD 6D 80                 .m. ; Get buffer address high byte from table
        sta     $01                             ; 80C1 85 01                    .. ; Store to temp_ptr high
L80C5           := * + 2
        jsr     ppu_buffer_check                           ; 80C3 20 DD 8E                  .. ; Process PPU buffer commands
        ldy     #$00                            ; 80C6 A0 00                    ..
        ldx     $0773                           ; 80C8 AE 73 07                 .s.
        cpx     #$06                            ; 80CB E0 06                    ..
        bne     nmi_clear_ppu_buf                           ; 80CD D0 01                    ..
        iny                                     ; 80CF C8                       .
nmi_clear_ppu_buf:  ldx     L8080,y                         ; 80D0 BE 80 80                 ...
        lda     #$00                            ; 80D3 A9 00                    ..
        sta     $0300,x                         ; 80D5 9D 00 03                 ...
        sta     $0301,x                         ; 80D8 9D 01 03                 ...
        sta     $0773                           ; 80DB 8D 73 07                 .s. ; Reset PPU update index
        lda     $0779                           ; 80DE AD 79 07                 .y. ; Load PPUMASK shadow
        sta     PPUMASK                         ; 80E1 8D 01 20                 .. ; Restore full PPUMASK (rendering on)
        jsr     sound_driver_update                           ; 80E4 20 D0 F2                  .. ; Call sound driver update
        jsr     read_controllers                           ; 80E7 20 5C 8E                  \. ; Read controller input
        jsr     pause_check                           ; 80EA 20 82 81                  .. ; Check for pause button
        jsr     score_compare                           ; 80ED 20 97 8F                  .. ; Compare scores (high score check)
        lda     $0776                           ; 80F0 AD 76 07                 .v. ; Load NMI control flags
        lsr     a                               ; 80F3 4A                       J ; Check bit 0 (pause flag)
        bcs     nmi_rng_update                           ; 80F4 B0 25                    .% ; If paused, skip timer/animation updates
        lda     $0747                           ; 80F6 AD 47 07                 .G. ; Load animation timer
        beq     nmi_timer_update                           ; 80F9 F0 05                    .. ; If zero, do full timer update
nmi_dec_anim_timer:  dec     $0747                           ; 80FB CE 47 07                 .G. ; Decrement animation timer
        bne     nmi_inc_frame                           ; 80FE D0 19                    .. ; If not zero yet, skip timer cascade
nmi_timer_update:  ldx     #$14                            ; 8100 A2 14                    .. ; X = 20 (number of fast timers)
        dec     $077F                           ; 8102 CE 7F 07                 ... ; Decrement base timer divider
        bpl     nmi_timer_loop                           ; 8105 10 07                    .. ; If still positive, use fast timers only
        lda     #$14                            ; 8107 A9 14                    .. ; Reset base timer to 20
        sta     $077F                           ; 8109 8D 7F 07                 ... ; Store timer_base reset value
        ldx     #$23                            ; 810C A2 23                    .# ; X = 35 (total timers including slow)
nmi_timer_loop:  lda     $0780,x                         ; 810E BD 80 07                 ... ; Load timer[X]
        beq     nmi_timer_next                           ; 8111 F0 03                    .. ; If already zero, skip
        dec     $0780,x                         ; 8113 DE 80 07                 ... ; Decrement timer[X]
nmi_timer_next:  dex                                     ; 8116 CA                       .
        bpl     nmi_timer_loop                           ; 8117 10 F5                    ..
nmi_inc_frame:  inc     $09                             ; 8119 E6 09                    .. ; Increment frame counter
nmi_rng_update:  ldx     #$00                            ; 811B A2 00                    .. ; X = 0 for RNG shift
        ldy     #$07                            ; 811D A0 07                    .. ; Y = 7 (8 bytes of RNG state)
        lda     $07A7                           ; 811F AD A7 07                 ... ; Load input_state_flags A
        and     #$02                            ; 8122 29 02                    ). ; Isolate bit 1
        sta     L0000                           ; 8124 85 00                    .. ; Store to temp
        lda     $07A8                           ; 8126 AD A8 07                 ... ; Load input_state_flags B
        and     #$02                            ; 8129 29 02                    ). ; Isolate bit 1
        eor     L0000                           ; 812B 45 00                    E. ; XOR with A flags (feedback bit)
        clc                                     ; 812D 18                       . ; Clear carry
        beq     nmi_rng_shift_loop                           ; 812E F0 01                    .. ; If XOR result zero, keep carry clear
nmi_rng_set_carry:  sec                                     ; 8130 38                       8 ; Set carry (feedback = 1)
nmi_rng_shift_loop:  ror     $07A7,x                         ; 8131 7E A7 07                 ~.. ; Rotate carry into RNG state byte
        inx                                     ; 8134 E8                       .
        dey                                     ; 8135 88                       .
        bne     nmi_rng_shift_loop                           ; 8136 D0 F9                    ..
        lda     $0722                           ; 8138 AD 22 07                 .". ; Check sprite hit flag
        beq     nmi_set_scroll                           ; 813B F0 1F                    .. ; If no sprite 0 hit needed, skip wait
nmi_wait_sprite0_clear:  lda     PPUSTATUS                       ; 813D AD 02 20                 .. ; Wait for sprite 0 flag to clear
        and     #$40                            ; 8140 29 40                    )@ ; Test sprite 0 hit bit
