        jsr     oam_clear_partial                           ; 814A 20 23 82                  #. ; Clear partial OAM (HUD sprites)
        jsr     hud_sprite_update                           ; 814D 20 C6 81                  .. ; Update HUD sprite positions
nmi_wait_sprite0_set:  lda     PPUSTATUS                       ; 8150 AD 02 20                 .. ; Wait for sprite 0 hit flag
        and     #$40                            ; 8153 29 40                    )@ ; Test sprite 0 hit bit
        beq     nmi_wait_sprite0_set                           ; 8155 F0 F9                    .. ; Loop until hit detected
        ldy     #$14                            ; 8157 A0 14                    .. ; Y = 20 (delay loop count)
nmi_sprite0_delay:  dey                                     ; 8159 88                       . ; Delay loop after sprite 0 hit
        bne     nmi_sprite0_delay                           ; 815A D0 FD                    .. ; Branch back for delay
nmi_set_scroll:  lda     $073F                           ; 815C AD 3F 07                 .?. ; Load scroll_x
        sta     PPUSCROLL                       ; 815F 8D 05 20                 .. ; Write horizontal scroll
        lda     $0740                           ; 8162 AD 40 07                 .@. ; Load scroll_y
        sta     PPUSCROLL                       ; 8165 8D 05 20                 .. ; Write vertical scroll
