; ---------------------------------------------------------------------------
; pause_check - Handle Start button pause/unpause
; Only active during gameplay (mode 1, submode 3) and battle (mode 2).
; Uses frame_delay for debouncing the Start button.
; ---------------------------------------------------------------------------
pause_check:  lda     $0770                           ; 8182 AD 70 07                 .p. ; Load game_mode
        cmp     #$02                            ; 8185 C9 02                    .. ; Is it mode 2 (battle)?
        beq     pause_check_delay                           ; 8187 F0 0B                    .. ; If battle mode, handle pause
        cmp     #$01                            ; 8189 C9 01                    .. ; Is it mode 1 (gameplay)?
        bne     pause_rts                           ; 818B D0 38                    .8 ; If not gameplay, skip pause handling
        lda     $0772                           ; 818D AD 72 07                 .r. ; Load game_submode
        cmp     #$03                            ; 8190 C9 03                    .. ; Is submode 3 (active play)?
        bne     pause_rts                           ; 8192 D0 31                    .1 ; If not active play, skip pause
pause_check_delay:  lda     $0777                           ; 8194 AD 77 07                 .w. ; Load frame delay counter
        beq     pause_check_input                           ; 8197 F0 04                    .. ; If zero, check input
        dec     $0777                           ; 8199 CE 77 07                 .w. ; Decrement delay (debounce)
        rts                                     ; 819C 60                       ` ; Return

; ----------------------------------------------------------------------------
