        and     #$10                            ; 81A0 29 10                    ). ; Test Start button (bit 4)
        beq     pause_unpause                           ; 81A2 F0 19                    .. ; If Start not pressed, handle unpause
        lda     $0776                           ; 81A4 AD 76 07                 .v. ; Load NMI control flags
        and     #$80                            ; 81A7 29 80                    ). ; Test pause-acknowledged bit
        bne     pause_rts                           ; 81A9 D0 1A                    .. ; If already acknowledged, return
        lda     #$2B                            ; 81AB A9 2B                    .+ ; Set frame delay = 43 frames
        sta     $0777                           ; 81AD 8D 77 07                 .w.
        lda     $0776                           ; 81B0 AD 76 07                 .v.
        tay                                     ; 81B3 A8                       .
        iny                                     ; 81B4 C8                       .
        sty     $FA                             ; 81B5 84 FA                    ..
        eor     #$01                            ; 81B7 49 01                    I. ; Toggle pause flag (bit 0)
        ora     #$80                            ; 81B9 09 80                    .. ; Set pause-acknowledged bit
        bne     pause_store_flags                           ; 81BB D0 05                    ..
pause_unpause:  lda     $0776                           ; 81BD AD 76 07                 .v.
        and     #$7F                            ; 81C0 29 7F                    ).
pause_store_flags:  sta     $0776                           ; 81C2 8D 76 07                 .v.
