; jump_table_dispatch - Indirect jump through inline table
; Usage:  LDA index / JSR jump_table_dispatch / .word addr0, addr1, ...
; Multiplies A by 2, pulls JSR return address from stack, reads the
; 16-bit target address from the table following the JSR, and jumps to it.
; ---------------------------------------------------------------------------
jump_table_dispatch:  asl     a                               ; 8E04 0A                       . ; A * 2 for 16-bit table index
        tay                                     ; 8E05 A8                       . ; Save index in Y
        pla                                     ; 8E06 68                       h ; Pull return address low byte
        sta     $04                             ; 8E07 85 04                    .. ; Store to dispatch_ret_addr low
        pla                                     ; 8E09 68                       h ; Pull return address high byte
        sta     $05                             ; 8E0A 85 05                    .. ; Store to dispatch_ret_addr high
        iny                                     ; 8E0C C8                       . ; Increment past JSR opcode
        lda     ($04),y                         ; 8E0D B1 04                    .. ; Read target address low from table
        sta     L0006                           ; 8E0F 85 06                    .. ; Store to dispatch_target low
        iny                                     ; 8E11 C8                       . ; Increment to high byte
        lda     ($04),y                         ; 8E12 B1 04                    .. ; Read target address high from table
        sta     $07                             ; 8E14 85 07                    .. ; Store to dispatch_target high
        jmp     (L0006)                         ; 8E16 6C 06 00                 l.. ; Jump indirect through dispatch_target

