        sta     JOY1                            ; 8E5E 8D 16 40                 ..@ ; Write strobe to JOY1
        lsr     a                               ; 8E61 4A                       J ; A = 0 (clear strobe)
        tax                                     ; 8E62 AA                       . ; X = 0 (controller 1)
        sta     JOY1                            ; 8E63 8D 16 40                 ..@ ; Write 0 to JOY1 (end strobe)
        jsr     read_single_controller                           ; 8E66 20 6A 8E                  j. ; Read controller 1
        inx                                     ; 8E69 E8                       . ; X = 1 for controller 2 (falls through)
read_single_controller:  ldy     #$08                            ; 8E6A A0 08                    .. ; Y = 8 (8 buttons to read)
read_ctrl_bit_loop:  pha                                     ; 8E6C 48                       H ; Save accumulator
        lda     JOY1,x                          ; 8E6D BD 16 40                 ..@ ; Read button state from port
        sta     L0000                           ; 8E70 85 00                    .. ; Store raw read
        lsr     a                               ; 8E72 4A                       J ; Shift bit into position
        ora     L0000                           ; 8E73 05 00                    .. ; OR with raw (handle DPCM conflict)
        lsr     a                               ; 8E75 4A                       J ; Shift result
        pla                                     ; 8E76 68                       h ; Restore accumulator
        rol     a                               ; 8E77 2A                       * ; Rotate button bit into A
        dey                                     ; 8E78 88                       . ; Decrement button counter
        bne     read_ctrl_bit_loop                           ; 8E79 D0 F1                    .. ; Loop for all 8 buttons
        sta     $06FC,x                         ; 8E7B 9D FC 06                 ... ; Store result to joy1_buttons or joy2_buttons
        pha                                     ; 8E7E 48                       H ; Save buttons
        and     #$30                            ; 8E7F 29 30                    )0 ; Isolate Select+Start bits
        and     $074A,x                         ; 8E81 3D 4A 07                 =J. ; AND with previous frame (detect held)
        beq     read_ctrl_store                           ; 8E84 F0 07                    .. ; If no directional conflict, keep as-is
        pla                                     ; 8E86 68                       h ; Restore buttons
        and     #$CF                            ; 8E87 29 CF                    ). ; Mask off Select+Start (prevent rapid fire)
        sta     $06FC,x                         ; 8E89 9D FC 06                 ... ; Store filtered buttons
        rts                                     ; 8E8C 60                       `

