; ---------------------------------------------------------------------------
; ram_init - Clear RAM pages $00-$07
; Fills RAM with zero. Skips stack page ($01) below $60 to preserve
; return addresses. Amount cleared depends on Y register on entry
; (warm boot preserves more RAM than cold boot).
; ---------------------------------------------------------------------------
ram_init:  ldx     #$07                            ; 90CC A2 07                    .. ; X = 7 (clear pages $00-$07)
        lda     #$00                            ; 90CE A9 00                    .. ; A = 0 (fill value)
        sta     L0006                           ; 90D0 85 06                    .. ; Set indirect pointer to page start
ram_init_page_loop:  stx     $07                             ; 90D2 86 07                    .. ; Store X as high byte of pointer
ram_init_byte_loop:  cpx     #$01                            ; 90D4 E0 01                    .. ; Check if page 1 (stack page)
        bne     ram_init_store                           ; 90D6 D0 04                    .. ; If not page 1, store normally
        cpy     #$60                            ; 90D8 C0 60                    .` ; On stack page, skip below $60
        bcs     ram_init_next                           ; 90DA B0 02                    .. ; If Y >= $60, skip (preserve stack)
ram_init_store:  sta     (L0006),y                       ; 90DC 91 06                    .. ; Store zero to (ptr),Y
ram_init_next:  dey                                     ; 90DE 88                       . ; Decrement Y
        cpy     #$FF                            ; 90DF C0 FF                    ..
        bne     ram_init_byte_loop                           ; 90E1 D0 F1                    ..
        dex                                     ; 90E3 CA                       . ; Decrement page counter
        bpl     ram_init_page_loop                           ; 90E4 10 EC                    .. ; Loop through all pages
        rts                                     ; 90E6 60                       ` ; Return

