; ---------------------------------------------------------------------------
; CPU Interrupt Vectors (at $FFFA-$FFFF)
;   $FFFA: NMI vector   -> $8082 (nmi_handler)
;   $FFFC: RESET vector -> $8000 (reset_handler)
;   $FFFE: IRQ vector   -> $FFF0 (unused)
; ---------------------------------------------------------------------------
VEC_NMI         := * + 2
        asl     L821F,x                         ; FFF8 1E 1F 82                 ...
        .byte   $80                             ; FFFB 80                       .
VEC_RESET:
        .word   $8000                           ; FFFC 00 80                    ..
VEC_IRQ:.word   $FFF0                           ; FFFE F0 FF                    ..
